import React from 'react';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { Briefcase, Calendar, ArrowRight } from 'lucide-react';

const Experience = () => {
  const navigate = useNavigate();

  const experiences = [
    {
      id: 0,
      company: "DigitalBee Labs",
      role: "Trainer Software Engineer",
      period: "2024 - Present",
      description: "Currently training and mentoring junior developers in modern web technologies and software engineering best practices.",
      skills: ["React", "JavaScript", "Teaching", "Mentoring", "Web Development"]
    },
    {
      id: 1,
      company: "TechNexus Solutions",
      role: "Senior Full-Stack Developer",
      period: "2021 - Present",
      description: "Leading a squad of 8 developers in migrating a legacy monolith into a serverless microservices architecture using AWS and React.",
      skills: ["React", "AWS", "Node.js", "Docker"]
    },
    {
      id: 2,
      company: "Innovate Digital",
      role: "Frontend Engineer",
      period: "2019 - 2021",
      description: "Spearheaded the redesign of the core dashboard, increasing user engagement by 35% and improving lighthouse scores by 40 points.",
      skills: ["Vue.js", "Tailwind CSS", "TypeScript", "Jest"]
    },
    {
      id: 3,
      company: "Launchpad Startups",
      role: "Junior Web Developer",
      period: "2018 - 2019",
      description: "Built responsive landing pages and internal admin tools. Optimized database queries for high-traffic real-time features.",
      skills: ["PHP", "JavaScript", "MySQL", "Sass"]
    }
  ];

  return (
    <section id="experience" className="py-24 bg-slate-100 dark:bg-darkCard/30">
      <div className="container mx-auto px-6">
        <div className="text-center mb-16">
          <h2 className="text-4xl font-bold mb-4">Work Experience</h2>
          <div className="w-20 h-1.5 bg-primary mx-auto rounded-full"></div>
        </div>

        <div className="max-w-4xl mx-auto relative">
          {/* Timeline Line */}
          <div className="absolute left-0 md:left-1/2 transform md:-translate-x-1/2 top-0 h-full w-1 bg-slate-300 dark:bg-slate-700 rounded-full"></div>

          {experiences.map((exp, index) => (
            <motion.div 
              key={index}
              initial={{ opacity: 0, y: 20 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ delay: index * 0.2 }}
              className={`relative mb-12 flex flex-col md:flex-row items-center ${index % 2 === 0 ? 'md:flex-row-reverse' : ''}`}
            >
              {/* Timeline Dot */}
              <div className="absolute left-0 md:left-1/2 transform md:-translate-x-1/2 w-6 h-6 bg-primary rounded-full border-4 border-white dark:border-darkBg z-10"></div>

              <div className={`w-full md:w-1/2 ${index % 2 === 0 ? 'md:pl-12' : 'md:pr-12'} pl-12`}>
                <div className="glass p-8 rounded-3xl shadow-lg border-l-4 border-primary">
                  <div className="flex items-center gap-2 mb-2 text-primary">
                    <Calendar size={16} />
                    <span className="text-sm font-semibold uppercase">{exp.period}</span>
                  </div>
                  <h3 className="text-2xl font-bold mb-1">{exp.role}</h3>
                  <div className="flex items-center gap-2 text-slate-500 mb-4">
                    <Briefcase size={16} />
                    <span className="font-medium">{exp.company}</span>
                  </div>
                  <p className="text-slate-600 dark:text-slate-400 mb-4">
                    {exp.description}
                  </p>
                  <div className="flex flex-wrap gap-2">
                    {exp.skills.map(skill => (
                      <span key={skill} className="px-3 py-1 bg-primary/5 text-primary text-xs font-bold rounded-lg border border-primary/10">
                        {skill}
                      </span>
                    ))}
                  </div>
                </div>
              </div>
            </motion.div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default Experience;
